import { useState } from 'react';

function Counter() {
  // useState returns [currentValue, setterFunction]
  // Array destructuring names them 'count' and 'setCount'
  const [count, setCount] = useState(0);

  return (
    <button onClick={() => setCount(count + 1)}>
      Clicked {count} times
    </button>
  );
}

