console.log(first);  // 88
console.log(fourth); // 95

let a = 1;
let b = 2;

// Old way — requires a temp variable
const temp = a;
a = b;
b = temp;

// With destructuring — one line, no temp variable
[a, b] = [b, a];

console.log(a); // 2
console.log(b); // 1

function minMax(numbers) {
  const sorted = [...numbers].sort((a, b) => a - b);
  return [sorted[0], sorted[sorted.length - 1]];
}

const [lowest, highest] = minMax([3, 1, 9, 2, 7]);
console.log(lowest);  // 1
console.log(highest); // 9

