import { useState, useTransition } from 'react';

function SearchBar({ onSearch }) {
  const [query, setQuery]             = useState('');
  const [results, setResults]         = useState([]);
  const [isLoading, setIsLoading]     = useState(false);
  const [isPending, startTransition]  = useTransition();

  async function handleChange(e) {
    const value = e.target.value;
    setQuery(value);

    if (value.length < 2) {
      setResults([]);
      return;
    }

    setIsLoading(true);
    startTransition(async () => {
      const data = await onSearch(value);
      setResults(data);
      setIsLoading(false);
    });
  }

  return (
    <div>
      <input value={query} onChange={handleChange} placeholder="Search..." />
      {(isLoading || isPending) && <span>Loading...</span>}
      <ul>
        {results.map(item => (
          <li key={item.id}>{item.name}</li>
        ))}
      </ul>
    </div>
  );
}

const arr = [1, 2, 3];

const { 0: first } = arr;   // ✅ works (object destructuring by numeric key)
const [first2] = arr;       // ✅ preferred — this is array destructuring

// The common mistake for newcomers:
const { first3 } = arr;     // ❌ first3 is undefined — arr has no property 'first3'

// ❌ Wrong order
const [setCount, count] = useState(0);
// setCount is now the number 0; count is the setter function
// count + 1 causes 'TypeError: count is not a function' later

// ✅ Correct order
const [count, setCount] = useState(0);

const data = null;
const [first] = data;       // ❌ TypeError: null is not iterable

const [first2] = data ?? []; // ✅ falls back to empty array if data is null/undefined

const [a, , b] = [1, 2, 3];  // skip second element
// a = 1, b = 3 (second element skipped, not defaulted)

const [x, y = 99] = [1];     // default for missing element
